    }
}

import java.util.*;
public class DetectSquares {
    Map<Integer,Map<Integer,Integer>> pts=new HashMap<>();
    void add(int[] p){pts.computeIfAbsent(p[0],k->new HashMap<>()).merge(p[1],1,Integer::sum);}
    int count(int[] q){
        int qx=q[0],qy=q[1],ans=0;
        Map<Integer,Integer> col=pts.getOrDefault(qx,new HashMap<>());
        for(Map.Entry<Integer,Integer> e:col.entrySet()){
            int py=e.getKey(); if(py==qy) continue;
            int side=py-qy;
            ans+=e.getValue()*pts.getOrDefault(qx+side,new HashMap<>()).getOrDefault(py,0)*pts.getOrDefault(qx+side,new HashMap<>()).getOrDefault(qy,0);
            ans+=e.getValue()*pts.getOrDefault(qx-side,new HashMap<>()).getOrDefault(py,0)*pts.getOrDefault(qx-side,new HashMap<>()).getOrDefault(qy,0);
        }
        return ans;
    }
    public static void main(String[] a){
        DetectSquares ds=new DetectSquares();
        ds.add(new int[]{3,10});ds.add(new int[]{11,2});ds.add(new int[]{3,2});
        System.out.println(ds.count(new int[]{11,10})); // 1
        ds.add(new int[]{14,8});
        System.out.println(ds.count(new int[]{11,2}));  // 0
        System.out.println("2D HashMap: x → (y → count). O(n) per query.");
    }
}

import java.util.*;
public class MyHashMap {
    static final int SIZE=1024;
    List<int[]>[] buckets=(List<int[]>[])new List[SIZE];
    int hash(int k){return k%SIZE;}
    void put(int k,int v){int h=hash(k);if(buckets[h]==null)buckets[h]=new ArrayList<>();for(int[] p:buckets[h])if(p[0]==k){p[1]=v;return;}buckets[h].add(new int[]{k,v});}
    int get(int k){int h=hash(k);if(buckets[h]==null)return -1;for(int[] p:buckets[h])if(p[0]==k)return p[1];return -1;}
    void remove(int k){int h=hash(k);if(buckets[h]==null)return;buckets[h].removeIf(p->p[0]==k);}
    public static void main(String[] a){
        MyHashMap m=new MyHashMap();m.put(1,1);m.put(2,2);
        System.out.println(m.get(1));    // 1
        System.out.println(m.get(3));    // -1
        m.put(2,1);System.out.println(m.get(2));   // 1
        m.remove(2);System.out.println(m.get(2));  // -1
        System.out.println("Chaining: bucket = array of (k,v) pairs. O(1) avg, O(n) worst");
    }
}

import java.util.*;
public class PrefixSum2D {
    int[][] prefix;
    PrefixSum2D(int[][] matrix){
        int m=matrix.length,n=matrix[0].length; prefix=new int[m+1][n+1];
        for(int i=1;i<=m;i++) for(int j=1;j<=n;j++)
            prefix[i][j]=matrix[i-1][j-1]+prefix[i-1][j]+prefix[i][j-1]-prefix[i-1][j-1];
    }
    int query(int r1,int c1,int r2,int c2){return prefix[r2+1][c2+1]-prefix[r1][c2+1]-prefix[r2+1][c1]+prefix[r1][c1];}
    public static void main(String[] a){
        PrefixSum2D ps=new PrefixSum2D(new int[][]{{3,0,1,4,2},{5,6,3,2,1},{1,2,0,1,5},{4,1,0,1,7},{1,0,3,0,5}});
        System.out.println(ps.query(2,1,4,3)); // 8
        System.out.println(ps.query(1,1,2,2)); // 11
        System.out.println("O(1) per query after O(mn) build");
    }
}

import java.util.*;
public class MutableKeyDanger {
    public static void main(String[] a){
        // WRONG: list as key — mutable!
        Map<List<Integer>,String> map=new HashMap<>();
        List<Integer> key=new ArrayList<>(Arrays.asList(1,2,3));
        map.put(key,"value");
        System.out.println(map.get(key)); // value ✓
        key.add(4); // MUTATE key!
        System.out.println(map.get(key)); // null ✗ — hash changed!
        System.out.println(map.get(Arrays.asList(1,2,3))); // null ✗ — original key gone!
        System.out.println("NEVER mutate HashMap keys. Use immutable: String, Integer, record.");
        System.out.println("If you need list as key: convert to sorted string first.");
    }
}

import java.util.*;
public class SnapshotArr {
    List<TreeMap<Integer,Integer>> data; int snapId=0;
    SnapshotArr(int length){data=new ArrayList<>();for(int i=0;i<length;i++){TreeMap<Integer,Integer> m=new TreeMap<>();m.put(0,0);data.add(m);}}
    void set(int index,int val){data.get(index).put(snapId,val);}
    int snap(){return snapId++;}
    int get(int index,int snap_id){return data.get(index).floorEntry(snap_id).getValue();}
    public static void main(String[] a){
        SnapshotArr sa=new SnapshotArr(3);
        sa.set(0,5);
        System.out.println(sa.snap()); // 0
        sa.set(0,6);
        System.out.println(sa.get(0,0)); // 5 (snap 0 value)
        System.out.println(sa.get(0,1)); // 6 (latest snap)
        System.out.println("TreeMap per index: floorEntry for binary search on snap_id");
    }
}

import java.util.*;
public class HashKeySynth {
    // Grid coordinate key
    static Map<String,Integer> buildGrid(int[][] cells){Map<String,Integer> m=new HashMap<>();for(int i=0;i<cells.length;i++)m.put(cells[i][0]+","+cells[i][1],i);return m;}
    // Anagram sorted key
    static Map<String,List<String>> groupAna(String[] words){Map<String,List<String>> m=new HashMap<>();for(String w:words){char[] c=w.toCharArray();Arrays.sort(c);m.computeIfAbsent(new String(c),k->new ArrayList<>()).add(w);}return m;}
    record Point(int x,int y){}
    public static void main(String[] a){
        var grid=buildGrid(new int[][]{{0,0},{1,2},{3,4}});System.out.println(grid.get("1,2"));
        System.out.println(groupAna(new String[]{"eat","tea","tan","ate","nat","bat"}).size());
        Map<Point,Integer> pts=new HashMap<>();pts.put(new Point(1,2),42);System.out.println(pts.get(new Point(1,2)));
        boolean ok=grid.get("1,2")==1&&groupAna(new String[]{"eat","tea","tan","ate","nat","bat"}).size()==3&&pts.get(new Point(1,2))==42;
        System.out.println("All pass: "+ok);
    }
}

import java.util.*;
public class T4Final {
    record Pt(int x,int y){}
    static Map<String,Integer> grid(int[][] c){Map<String,Integer> m=new HashMap<>();for(int i=0;i<c.length;i++)m.put(c[i][0]+","+c[i][1],i);return m;}
    static List<List<String>> grpAna(String[] s){Map<String,List<String>> m=new HashMap<>();for(String w:s){char[]c=w.toCharArray();Arrays.sort(c);m.computeIfAbsent(new String(c),k->new ArrayList<>()).add(w);}return new ArrayList<>(m.values());}
    // Design HashMap basic
    static class HM{List<int[]>[] b=(List<int[]>[])new List[64];int h(int k){return k&63;}void put(int k,int v){if(b[h(k)]==null)b[h(k)]=new ArrayList<>();for(int[] p:b[h(k)])if(p[0]==k){p[1]=v;return;}b[h(k)].add(new int[]{k,v});}int get(int k){if(b[h(k)]==null)return -1;for(int[] p:b[h(k)])if(p[0]==k)return p[1];return -1;}}
    public static void main(String[] a){
        System.out.println("grid="+grid(new int[][]{{0,0},{1,2}}).get("1,2"));
        System.out.println("grpAna="+grpAna(new String[]{"eat","tea","tan","ate"}).size());
        HM hm=new HM();hm.put(1,100);hm.put(2,200);System.out.println("hm="+hm.get(1));
        Map<Pt,Integer> pts=new HashMap<>();pts.put(new Pt(3,4),7);System.out.println("record="+pts.get(new Pt(3,4)));
        boolean ok=grid(new int[][]{{0,0},{1,2}}).get("1,2")==1&&grpAna(new String[]{"eat","tea","tan","ate"}).size()==2&&hm.get(1)==100&&pts.get(new Pt(3,4))==7;
        System.out.println("All pass: "+ok);
    }
}
